              trial_id: payload.trial_id,
              destination,
              processResult,
              ...payload.uploadInput,
            }))
          )
        : [
            await triggerByTaskAndWait("upload-task", {
              trial_id: payload.trial_id,
              destination: payload.uploadDestinations?.[0] ?? "default",
              processResult,
              ...payload.uploadInput,
            }),
          ];

      return {
        status: "success",
        downloadResult,
        processResult,
        uploadResults,
      };
    } catch (error) {
      logger.error("Media pipeline failed", {
        trial_id: payload.trial_id,
        error,
      });

      return {
        status: "failure",
        error: error instanceof Error ? error.message : String(error),
      };
    }
  },
});

